module top_module(
    input clk,
    input [3:0] parallel_in,
    input serial_in,
    output serial_out
);reg [3:0] obf_register;

always @(posedge clk) begin
    if (parallel_in) begin
        obf_register <= parallel_in;
    end else begin
        obf_register <= {obf_register[2:0], serial_in};
    end
end

assign serial_out = obf_register[0];

endmodule
